import{_ as a,o as t,c as n,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Smart Recommendations","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/recommendations.md","filePath":"analytics/recommendations.md"}'),i={name:"analytics/recommendations.md"};function r(s,e,l,c,m,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="smart-recommendations" tabindex="-1">Smart Recommendations <a class="header-anchor" href="#smart-recommendations" aria-label="Permalink to &quot;Smart Recommendations&quot;">​</a></h1><p>The app uses the word <strong>recommendations</strong> for three different surfaces. They are related, but they are not the same thing.</p><p>For the general locked/active premium behavior, see <a href="./../subscriptions/premium-features.html">Premium Features</a>. This page separates the three recommendation areas so you know what each one does.</p><blockquote><p>Screenshot placeholder: <code>premium-recs-locked.png</code> (S54 locked view)</p><p>Screenshot placeholder: <code>premium-recs-active.png</code> (S54 active view)</p></blockquote><h2 id="_1-alliance-recommendations" tabindex="-1">1. Alliance recommendations <a class="header-anchor" href="#_1-alliance-recommendations" aria-label="Permalink to &quot;1. Alliance recommendations&quot;">​</a></h2><p>These live inside <a href="./alliance.html">Alliance Analytics</a>.</p><p>When active, they can show:</p><ul><li>an inactivity watchlist</li><li>follow-up suggestions for players whose participation is low or whose activity pattern looks weak</li></ul><p>When not active, the Alliance tab shows a notice saying alliance recommendations are locked.</p><p>This is a premium surface.</p><h2 id="_2-player-recommendations" tabindex="-1">2. Player recommendations <a class="header-anchor" href="#_2-player-recommendations" aria-label="Permalink to &quot;2. Player recommendations&quot;">​</a></h2><p>Player-related recommendations appear in premium analytics and event views where the app can flag people who need attention.</p><p>In practice, these are used to point out players who may need:</p><ul><li>follow-up</li><li>review</li></ul><p>This is also a premium surface. It depends on premium recommendation features and is separate from the non-premium cleanup suggestions below.</p><h2 id="_3-cleanup-recommendations" tabindex="-1">3. Cleanup recommendations <a class="header-anchor" href="#_3-cleanup-recommendations" aria-label="Permalink to &quot;3. Cleanup recommendations&quot;">​</a></h2><p>Cleanup suggestions appear in usage or quota panels. They are not part of the analytics tabs and they are <strong>not</strong> premium-only.</p><p>They help you reduce usage by pointing out safe cleanup targets, and eligible roles can run the cleanup action from there.</p><p>Typical examples are storage or history areas that have grown large enough to deserve attention.</p><h2 id="why-this-distinction-matters" tabindex="-1">Why this distinction matters <a class="header-anchor" href="#why-this-distinction-matters" aria-label="Permalink to &quot;Why this distinction matters&quot;">​</a></h2><p>If someone says &quot;recommendations are missing,&quot; first check <strong>which kind</strong> they mean:</p><ul><li>analytics follow-up recommendations for alliances</li><li>player-focused recommendations in premium analytics or event views</li><li>cleanup suggestions in the usage panel</li></ul><p>They do not unlock together in the same way.</p><h2 id="related-guides" tabindex="-1">Related guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related guides&quot;">​</a></h2><ul><li><a href="./alliance.html">Alliance Analytics</a></li><li><a href="./player-cross-event.html">Player Cross-Event Analytics</a></li><li><a href="./../subscriptions/premium-features.html">Premium Features</a></li></ul>',25)])])}const u=a(i,[["render",r]]);export{d as __pageData,u as default};
